248→export const useFollowMutation = (session) =>{
249→    const queryClient = useQueryClient();
250→
251→    return useMutation({
252→        mutationFn: (data) => addFollows(data, session?.access_token),
253→
254→        onMutate: async(data) => {
255→            await queryClient.cancelQueries(['followsData']);
256→            const previousData = queryClient.getQueryData(['followsData']);
257→
258→            queryClient.setQueryData(['followsData'], (old) => {
259→                if(!old) return old;
260→                return{
261→                    ...old,
262→                    followersCount: old.isFollowing ? old.followersCount - 1 : old.followersCount + 1,
263→                    isFollowing: !old.isFollowing
264→                }
265→            })
266→
267→            return {previousData};
268→
269→        },
270→        onError: (err, data, context) => {
271→            queryClient.setQueryData(['followsData'], context.previousData)
272→        },
273→        onSettled: () => {
274→            queryClient.invalidateQueries(['followsData']);
275→        }
276→    })
277→}
