 50→const parseColor = (value, fallback) => {
 51→    if(typeof value !== "string"){
 52→        return fallback;
 53→    }
 54→
 55→    const trimmed = value.trim();
 56→    if(!trimmed){
 57→        return fallback;
 58→    }
 59→
 60→    return trimmed;
