339→    if(itemsError){
340→        console.error("supabase error while reading freedom wall items:", itemsError.message);
341→        throw {status: 500, error: "failed to fetch freedom wall items"};
342→    }
343→
344→    const hasMore = (items || []).length > parsedLimit;
345→    const slicedItems = hasMore ? items.slice(0, parsedLimit) : (items || []);
346→    const nextCursor = hasMore
347→        ? slicedItems[slicedItems.length - 1]?.created_at || null
348→        : null;
349→
350→    return {
351→        data: slicedItems,
352→        hasMore: hasMore,
353→        nextCursor: nextCursor
